// State + data helpers shared by the vanilla-js, React and Vue builds. Both
// charts are driven directly through their chart.id, so the wiring is one
// implementation for all three formats.
var MONTHS = [
  'Jan',
  'Feb',
  'Mar',
  'Apr',
  'May',
  'Jun',
  'Jul',
  'Aug',
  'Sep',
  'Oct',
  'Nov',
  'Dec',
]
var INITIAL = {
  labels: ['Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun', 'Jul'],
  values: [42, 61, 45, 78, 52, 89, 66],
}

var state = {
  labels: INITIAL.labels.slice(),
  values: INITIAL.values.slice(),
  monthCursor: INITIAL.labels.length, // next month to append
  insertCount: 0,
}

// Deterministic "random" value so the demo replays identically.
function nextValue(seed) {
  return 30 + ((seed * 37) % 60)
}

function monthLabel(i) {
  var name = MONTHS[i % 12]
  return i > 11 ? name + " '26" : name
}

function speed() {
  return document.getElementById('dt-slow').checked ? 1800 : 650
}

function pushState() {
  var barChart = ApexCharts.getChartByID('dtBar')
  var areaChart = ApexCharts.getChartByID('dtArea')
  if (!barChart || !areaChart) return

  var payload = {
    chart: { animations: { dynamicAnimation: { speed: speed() } } },
    xaxis: { categories: state.labels.slice() },
  }
  barChart.updateOptions(
    Object.assign(
      { series: [{ name: 'Revenue', data: state.values.slice() }] },
      payload,
    ),
    false,
    true,
  )
  areaChart.updateOptions(
    Object.assign(
      {
        series: [
          {
            name: 'Users',
            data: state.values.map(function (v) {
              return Math.round(v * 0.6 + 10)
            }),
          },
        ],
      },
      payload,
    ),
    false,
    true,
  )
  syncButtons()
}

function syncButtons() {
  document.getElementById('dt-add').disabled = state.labels.length >= 20
  document.getElementById('dt-insert').disabled = state.labels.length >= 20
  document.getElementById('dt-remove-last').disabled = state.labels.length <= 3
  document.getElementById('dt-remove-mid').disabled = state.labels.length <= 3
}

// Attach every button, then set the initial disabled state. Returns a cleanup
// function that detaches the listeners (used by the React/Vue teardown).
function wireDynamicData() {
  var handlers = []
  function on(id, fn) {
    var el = document.getElementById(id)
    if (!el) return
    el.addEventListener('click', fn)
    handlers.push({ el: el, fn: fn })
  }

  on('dt-add', function () {
    state.labels.push(monthLabel(state.monthCursor))
    state.values.push(nextValue(state.monthCursor))
    state.monthCursor++
    pushState()
  })

  on('dt-insert', function () {
    var at = Math.floor(state.labels.length / 2)
    state.insertCount++
    state.labels.splice(at, 0, 'New ' + state.insertCount)
    state.values.splice(at, 0, nextValue(state.insertCount * 5 + 3))
    pushState()
  })

  on('dt-remove-last', function () {
    state.labels.pop()
    state.values.pop()
    pushState()
  })

  on('dt-remove-mid', function () {
    var at = Math.floor(state.labels.length / 2)
    state.labels.splice(at, 1)
    state.values.splice(at, 1)
    pushState()
  })

  on('dt-rotate', function () {
    state.values.push(state.values.shift())
    pushState()
  })

  on('dt-reset', function () {
    state.labels = INITIAL.labels.slice()
    state.values = INITIAL.values.slice()
    state.monthCursor = INITIAL.labels.length
    state.insertCount = 0
    pushState()
  })

  syncButtons()

  return function () {
    handlers.forEach(function (h) {
      h.el.removeEventListener('click', h.fn)
    })
  }
}

var options = {
  series: [
    {
      name: 'Revenue',
      data: [42, 61, 45, 78, 52, 89, 66],
    },
  ],
  chart: {
