// Both charts are already rendered here, so wire the buttons straight away.
// (All the state + helpers live in the shared head script.)
wireDynamicData()

.dt-wrap {
  max-width: 780px;
  margin: 14px auto;
  font-family: Helvetica, Arial, sans-serif;
}
.dt-bar {
  display: flex;
  gap: 8px;
  align-items: center;
  flex-wrap: wrap;
  margin: 4px 6px 14px;
}
.dt-bar button {
  padding: 6px 13px;
  cursor: pointer;
  border: 1px solid #6366f1;
  color: #4338ca;
  background: #fff;
  border-radius: 6px;
  font-size: 13px;
  font-weight: 600;
}
.dt-bar button:disabled {
  opacity: 0.45;
  cursor: default;
}
.dt-bar label {
  font-size: 13px;
  color: #445;
  margin-left: 6px;
  user-select: none;
}
.dt-card {
  border: 1px solid #e4e7f2;
  border-radius: 8px;
  padding: 6px;
  background: #fff;
  margin-bottom: 10px;
}
/* The shared demo stylesheet gives the FIRST chart container (#chart) a
     white panel + border; the cards style both charts uniformly instead. */
#chart {
  padding: 0;
  background: transparent;
  border: 0;
  box-shadow: none;
}
.dt-note {
  background: #eef2ff;
  border-left: 3px solid #6366f1;
  padding: 11px 15px;
  font-size: 13px;
  color: #234;
  border-radius: 2px;
  line-height: 1.6;
  margin: 14px 6px;
}
.dt-note code {
  background: #dfe3ff;
  padding: 1px 5px;
  border-radius: 3px;
}
